rollback.sql:
CREATE TYPE public."systemtype" AS ENUM ('NONE', 'ON_PREMISE', 'CLOUD', 'ETL', 'MA', 'COTS', 'HOME_GROWN');

-- update systems table
UPDATE systems SET system_type = 'NONE' WHERE system_type IN ('CUSTOM_COTS', 'MOBILE');
UPDATE systems SET system_type = 'CLOUD' WHERE deployment_type = 'CLOUD';
UPDATE systems SET system_type = 'ON_PREMISE' WHERE deployment_type = 'ON_PREMISE';
UPDATE systems SET system_type = 'MA' WHERE is_ma_asset = true;
UPDATE systems SET system_type = 'ETL' WHERE is_etl = true;

ALTER TABLE systems ALTER COLUMN system_type TYPE systemtype_new USING (system_type::text::systemtype_new);
ALTER TABLE systems DROP COLUMN deployment_type;

-- update bigid_dstype_system_type_mappings table
UPDATE bigid_dstype_system_type_mappings SET system_type = 'NONE' WHERE system_type IN ('CUSTOM_COTS', 'MOBILE');
ALTER TABLE bigid_dstype_system_type_mappings ALTER COLUMN system_type TYPE systemtype_new USING (system_type::text::systemtype_new);

-- update systemtype type
DROP TYPE systemtype;
ALTER TYPE systemtype_new RENAME TO systemtype;

DROP TYPE "deploymenttype";
